 1→import express from 'express';
 2→import http from 'http';
 3→import cors from 'cors';
 4→import { Server } from 'socket.io';
 5→import { RoomManager } from './room-manager';
 6→import { registerConnectionHandlers } from './handlers/connection';
 7→import { registerLobbyHandlers } from './handlers/lobby';
 8→import { registerGameHandlers } from './handlers/game';
 9→
10→const PORT = process.env.PORT || 3000;
11→
12→const app = express();
13→app.use(cors());
14→
15→const server = http.createServer(app);
16→
17→const io = new Server(server, {
18→  cors: {
19→    origin: '*',
20→    methods: ['GET', 'POST'],
21→  },
22→});
23→
24→const roomManager = new RoomManager();
25→
26→// Health check endpoint
27→app.get('/', (_req, res) => {
28→  res.json({ status: 'ok', game: 'Basra' });
29→});
30→
31→io.on('connection', (socket) => {
32→  console.log(`Client connected: ${socket.id}`);
33→
34→  registerConnectionHandlers(io, socket, roomManager);
35→  registerLobbyHandlers(io, socket, roomManager);
36→  registerGameHandlers(io, socket, roomManager);
37→});
38→
39→// Cleanup stale rooms every 10 minutes
40→setInterval(() => {
41→  roomManager.cleanupStaleRooms();
42→}, 10 * 60 * 1000);
43→
