  1→import { useState, useEffect, useCallback, useRef } from 'react';
  2→import { View, StyleSheet, SafeAreaView, Text } from 'react-native';
  3→import { useRouter } from 'expo-router';
  4→import { useSocket } from '../src/hooks/useSocket';
  5→import { useGameStore } from '../src/store/useGameStore';
  6→import { useAppStore } from '../src/store/useAppStore';
  7→import ScoreBar from '../src/components/ScoreBar';
  8→import TurnIndicator from '../src/components/TurnIndicator';
  9→import GameBoard from '../src/components/GameBoard';
 10→import BasraToast from '../src/components/BasraToast';
 11→import { colors, spacing, fontSize } from '../src/theme';
 12→
 13→export default function GameScreen() {
 14→  const router = useRouter();
 15→  const { playCard: emitPlayCard } = useSocket();
 16→  const {
 17→    hand,
 18→    table,
 19→    deckRemaining,
 20→    currentTurn,
 21→    myId,
 22→    opponentCardCount,
 23→    roundNumber,
 24→    targetScore,
 25→    players,
 26→    lastPlay,
 27→    lastCapturePlayerId,
 28→    phase,
 29→    opponentConnected,
 30→  } = useGameStore();
 31→
 32→  const [showBasra, setShowBasra] = useState(false);
 33→  const [isJackBasra, setIsJackBasra] = useState(false);
 34→  const navigatedRef = useRef(false);
 35→
 36→  const isMyTurn = currentTurn === myId;
 37→  const me = players.find((p) => p.id === myId);
 38→  const opponent = players.find((p) => p.id !== myId);
 39→
 40→  // Reset navigation guard when we return to playing
 41→  useEffect(() => {
 42→    if (phase === 'playing') {
 43→      navigatedRef.current = false;
 44→    }
 45→  }, [phase]);
 46→
 47→  // Navigate to score screen after round-end animation completes
 48→  const onRoundEndAnimDone = useCallback(() => {
 49→    if (!navigatedRef.current) {
 50→      navigatedRef.current = true;
 51→      router.push('/score');
 52→    }
 53→  }, [router]);
 54→
 55→  // Fallback: navigate after timeout if animation callback doesn't fire
 56→  useEffect(() => {
 57→    if (phase === 'round-end' || phase === 'game-over') {
 58→      const timer = setTimeout(() => {
 59→        if (!navigatedRef.current) {
 60→          navigatedRef.current = true;
 61→          router.push('/score');
 62→        }
 63→      }, 2500);
 64→      return () => clearTimeout(timer);
 65→    }
 66→  }, [phase]);
 67→
 68→  // Show basra toast when a basra occurs
 69→  useEffect(() => {
 70→    if (lastPlay && (lastPlay.isBasra || lastPlay.isJackBasra)) {
 71→      setIsJackBasra(lastPlay.isJackBasra);
 72→      setShowBasra(true);
 73→    }
 74→  }, [lastPlay]);
 75→
 76→  if (!me || !opponent) {
 77→    return (
 78→      <View style={styles.container}>
 79→        <Text style={styles.loadingText}>Loading...</Text>
 80→      </View>
 81→    );
 82→  }
 83→
 84→  return (
 85→    <SafeAreaView style={styles.container}>
 86→      <ScoreBar
 87→        myScore={me.score}
 88→        opponentScore={opponent.score}
 89→        myName={me.nickname}
 90→        opponentName={opponent.nickname}
 91→        targetScore={targetScore}
 92→        roundNumber={roundNumber}
 93→        deckRemaining={deckRemaining}
 94→      />
 95→
 96→      {!opponentConnected && (
 97→        <View style={styles.disconnectBanner}>
 98→          <Text style={styles.disconnectText}>Opponent disconnected...</Text>
 99→        </View>
100→      )}
101→
102→      <TurnIndicator isMyTurn={isMyTurn} />
103→
104→      <GameBoard
105→        hand={hand}
106→        table={table}
107→        opponentCardCount={opponentCardCount}
108→        deckRemaining={deckRemaining}
109→        isMyTurn={isMyTurn}
110→        myId={myId}
111→        phase={phase}
112→        lastCapturePlayerId={lastCapturePlayerId}
113→        myCapturedCount={me.capturedCount}
114→        myBasras={me.basras}
115→        myJackBasras={me.jackBasras}
116→        opponentCapturedCount={opponent.capturedCount}
117→        opponentBasras={opponent.basras}
118→        opponentJackBasras={opponent.jackBasras}
119→        onPlayCard={emitPlayCard}
120→        onRoundEndAnimDone={onRoundEndAnimDone}
121→      />
122→
123→      <BasraToast
124→        visible={showBasra}
125→        isJackBasra={isJackBasra}
126→        onHide={() => setShowBasra(false)}
127→      />
128→    </SafeAreaView>
129→  );
130→}
