  1→import { useState, useCallback, useMemo } from 'react';
  2→import type { LayoutChangeEvent } from 'react-native';
  3→import { cardDimensions } from '../theme';
  4→import type { BoardDimensions, GameLayout, ZoneLayout } from './types';
  5→
  6→const CARD_W = cardDimensions.width;
  7→const CARD_H = cardDimensions.height;
  8→const SMALL_SCALE = 0.7;
  9→const SMALL_W = CARD_W * SMALL_SCALE;
 10→const SMALL_H = CARD_H * SMALL_SCALE;
 11→
 12→/**
 13→ * Hand fan: cards spread with ~55px gap (max),
 14→ * slight parabolic arc (6px height), rotation ±0.04rad from center.
 15→ */
 16→export function getHandPositions(
 17→  count: number,
 18→  zoneCenter: { x: number; y: number },
 19→  maxGap: number = 55
 20→): { x: number; y: number; rotation: number }[] {
 21→  if (count === 0) return [];
 22→  const gap = Math.min(maxGap, 55);
 23→  const totalWidth = gap * (count - 1);
 24→  const startX = zoneCenter.x - totalWidth / 2;
 25→  const positions: { x: number; y: number; rotation: number }[] = [];
 26→
 27→  for (let i = 0; i < count; i++) {
 28→    const t = count === 1 ? 0 : (i / (count - 1)) * 2 - 1; // -1 to 1
 29→    positions.push({
 30→      x: startX + i * gap,
 31→      y: zoneCenter.y + Math.abs(t) * 6, // gentle arc
 32→      rotation: t * 0.04,
 33→    });
 34→  }
 35→  return positions;
 36→}
 37→
 38→/**
 39→ * Opponent hand: smaller, tighter spacing.
 40→ */
 41→export function getOpponentHandPositions(
 42→  count: number,
 43→  zoneCenter: { x: number; y: number }
 44→): { x: number; y: number; rotation: number }[] {
 45→  if (count === 0) return [];
 46→  const gap = 28;
 47→  const totalWidth = gap * (count - 1);
 48→  const startX = zoneCenter.x - totalWidth / 2;
 49→  const positions: { x: number; y: number; rotation: number }[] = [];
 50→
 51→  for (let i = 0; i < count; i++) {
 52→    const t = count === 1 ? 0 : (i / (count - 1)) * 2 - 1;
 53→    positions.push({
 54→      x: startX + i * gap,
 55→      y: zoneCenter.y + Math.abs(t) * 3,
 56→      rotation: t * 0.03,
 57→    });
 58→  }
 59→  return positions;
 60→}
 61→
 62→/**
 63→ * Table scatter: centered grid with ±6px jitter for organic feel.
 64→ */
 65→export function getTablePositions(
 66→  count: number,
 67→  zone: ZoneLayout
 68→): { x: number; y: number; rotation: number }[] {
 69→  if (count === 0) return [];
 70→  const cols = Math.min(5, count);
 71→  const colGap = SMALL_W + 12;
 72→  const rowGap = SMALL_H + 8;
 73→  const rows = Math.ceil(count / cols);
 74→  const gridWidth = cols * colGap;
 75→  const gridHeight = rows * rowGap;
 76→
 77→  // Center the grid both horizontally and vertically in the zone
 78→  const baseX = zone.x + (zone.width - gridWidth) / 2 + colGap / 2;
 79→  const baseY = zone.y + (zone.height - gridHeight) / 2 + rowGap / 2;
 80→
 81→  const positions: { x: number; y: number; rotation: number }[] = [];
 82→
 83→  for (let i = 0; i < count; i++) {
 84→    const col = i % cols;
 85→    const row = Math.floor(i / cols);
 86→    // Deterministic jitter from index
 87→    const jx = ((i * 7 + 3) % 13) - 6;
 88→    const jy = ((i * 11 + 5) % 13) - 6;
 89→    const jr = ((i * 13 + 2) % 9 - 4) * 0.015;
 90→    positions.push({
 91→      x: baseX + col * colGap + jx,
 92→      y: baseY + row * rowGap + jy,
 93→      rotation: jr,
 94→    });
 95→  }
 96→  return positions;
 97→}
