 99→export function useGameLayout() {
100→  const [board, setBoard] = useState<BoardDimensions>({ width: 0, height: 0 });
101→
102→  const onBoardLayout = useCallback((e: LayoutChangeEvent) => {
103→    const { width, height } = e.nativeEvent.layout;
104→    setBoard({ width, height });
105→  }, []);
106→
107→  const layout = useMemo<GameLayout | null>(() => {
108→    if (board.width === 0 || board.height === 0) return null;
109→    const { width: W, height: H } = board;
110→
111→    const opponentHand: ZoneLayout = {
112→      x: 0,
113→      y: 0,
114→      width: W,
115→      height: H * 0.08,
116→    };
117→
118→    const opponentPile: ZoneLayout = {
119→      x: W - 56,
120→      y: H * 0.09,
121→      width: 46,
122→      height: 64,
123→    };
124→
125→    const table: ZoneLayout = {
126→      x: 12,
127→      y: H * 0.17,
128→      width: W - 24,
129→      height: H * 0.40,
130→    };
131→
132→    const deck: ZoneLayout = {
133→      x: 16,
134→      y: H * 0.61,
135→      width: CARD_W + 10,
136→      height: CARD_H + 10,
137→    };
138→
139→    const myPile: ZoneLayout = {
140→      x: W - 56,
141→      y: H * 0.61,
142→      width: 46,
143→      height: 64,
144→    };
145→
146→    const myHand: ZoneLayout = {
147→      x: 0,
148→      y: H * 0.76,
149→      width: W,
150→      height: H * 0.24,
151→    };
152→
153→    return {
154→      board,
155→      opponentHand,
156→      opponentPile,
157→      table,
158→      deck,
159→      myPile,
160→      myHand,
161→    };
