  1→import axios, {
  2→  AxiosError,
  3→  AxiosInstance,
  4→  InternalAxiosRequestConfig,
  5→} from "axios";
  6→import { config } from "@/constants/config";
  7→import { secureStorage } from "./storage";
  8→import { ApiError, ApiResponse, AuthTokens } from "@/types";
  9→
 10→let isRefreshing = false;
 11→let failedQueue: Array<{
 12→  resolve: (token: string) => void;
 13→  reject: (error: Error) => void;
 14→}> = [];
 15→
 16→function processQueue(error: Error | null, token: string | null) {
 17→  failedQueue.forEach((request) => {
 18→    if (error) {
 19→      request.reject(error);
 20→    } else {
 21→      request.resolve(token!);
 22→    }
 23→  });
 24→  failedQueue = [];
 25→}
 26→
 27→function createApiClient(): AxiosInstance {
 28→  const client = axios.create({
 29→    baseURL: config.API_URL,
 30→    timeout: 15000,
 31→    adapter: "fetch",
 32→    headers: {
 33→      "Content-Type": "application/json",
 34→      Accept: "application/json",
 35→    },
 36→  });
 37→
 38→  // ─── Request Interceptor: Attach Access Token ──────────────
 39→
 40→  client.interceptors.request.use(
 41→    async (requestConfig: InternalAxiosRequestConfig) => {
 42→      const token = await secureStorage.getAccessToken();
 43→      if (token) {
 44→        requestConfig.headers.Authorization = `Bearer ${token}`;
 45→      }
 46→      return requestConfig;
 47→    },
 48→    (error) => Promise.reject(error)
 49→  );
 50→
 51→  // ─── Response Interceptor: Handle 401 + Token Refresh ──────
 52→
 53→  client.interceptors.response.use(
 54→    (response) => response,
 55→    async (error: AxiosError<ApiError>) => {
 56→      const originalRequest = error.config as InternalAxiosRequestConfig & {
 57→        _retry?: boolean;
 58→      };
 59→
 60→      if (error.response?.status === 401 && !originalRequest._retry) {
 61→        if (isRefreshing) {
 62→          return new Promise<string>((resolve, reject) => {
 63→            failedQueue.push({ resolve, reject });
 64→          }).then((token) => {
 65→            originalRequest.headers.Authorization = `Bearer ${token}`;
 66→            return client(originalRequest);
 67→          });
 68→        }
 69→
 70→        originalRequest._retry = true;
 71→        isRefreshing = true;
 72→
 73→        try {
 74→          const tokens = await secureStorage.getTokens();
 75→          if (!tokens?.refreshToken) {
 76→            throw new Error("No refresh token available");
 77→          }
 78→
 79→          const { data } = await axios.post<ApiResponse<AuthTokens>>(
 80→            `${config.API_URL}/auth/refresh`,
 81→            { refreshToken: tokens.refreshToken }
 82→          );
 83→
 84→          await secureStorage.saveTokens(data.data);
 85→          processQueue(null, data.data.accessToken);
 86→
 87→          originalRequest.headers.Authorization = `Bearer ${data.data.accessToken}`;
 88→          return client(originalRequest);
 89→        } catch (refreshError) {
 90→          processQueue(refreshError as Error, null);
 91→          await secureStorage.clearTokens();
 92→          // The auth store will detect missing tokens and redirect to login
 93→          throw refreshError;
 94→        } finally {
 95→          isRefreshing = false;
 96→        }
 97→      }
 98→
 99→      return Promise.reject(error);
100→    }
101→  );
102→
103→  return client;
104→}
105→
106→export const api = createApiClient();
