108→// ─── Typed Request Helpers ───────────────────────────────────
109→
110→export async function apiGet<T>(url: string, params?: object): Promise<T> {
111→  const response = await api.get<ApiResponse<T>>(url, { params });
112→  return response.data.data;
113→}
