    shadowColor: '#000',
    shadowOffset: { width: 0, height: 1 },
    shadowRadius: 2,
    elevation: 2,
  },
  countBadge: {
    marginTop: 3,
    backgroundColor: colors.surface,
    borderRadius: 8,
    paddingHorizontal: 6,
    paddingVertical: 1,
  },
  countText: {
    fontSize: fontSize.xs,
    fontWeight: '700',
    color: colors.textDim,
  },
  badges: {
    flexDirection: 'row',
    gap: 3,
    marginTop: 2,
  },
  basraDot: {
    backgroundColor: 'rgba(233, 69, 96, 0.2)',
    borderRadius: 6,
    paddingHorizontal: 4,
    paddingVertical: 1,
  },
  basraText: {
    fontSize: 8,
    fontWeight: '800',
    color: colors.primary,
  },
  jackDot: {
    backgroundColor: 'rgba(240, 192, 64, 0.2)',
