const isWeb = Platform.OS === 'web';

async function safeHaptic(fn: () => Promise<void>) {
  if (isWeb) return;
  try {
    const Haptics = require('expo-haptics');
    await fn.call(null);
  } catch {}
}

export function lightTap() {
  if (isWeb) return;
  const Haptics = require('expo-haptics');
  Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
}

